import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import InAppPurchase from 'react-native-iap';

const PaymentModule = () => {
  const [products, setProducts] = useState([]);

  const fetchProducts = async () => {
    const productIds = ['product1', 'product2'];
    const products = await InAppPurchase.getProducts(productIds);
    setProducts(products);
  };

  const handlePurchase = async (productId) => {
    const purchase = await InAppPurchase.purchaseProduct(productId);
    console.log(purchase);
  };

  return (
    <View>
      <Text>Payment Module</Text>
      <Button title="Fetch Products" onPress={fetchProducts} />
      <Button title="Purchase Product" onPress={() => handlePurchase(products[0].productId)} />
    </View>
  );
};

export default PaymentModule;